// Only proceed on the 1st of the month
const now = new Date();
const dayOfMonth = now.getUTCDate();

if (dayOfMonth !== 1) {
  // Not the 1st — skip execution
  return [];
}

// Calculate PREVIOUS month's billing period
const year = now.getUTCMonth() === 0 ? now.getUTCFullYear() - 1 : now.getUTCFullYear();
const month = now.getUTCMonth() === 0 ? 12 : now.getUTCMonth(); // getUTCMonth is 0-indexed
const billingMonth = `${year}-${String(month).padStart(2, '0')}`;

const periodStart = new Date(Date.UTC(year, month - 1, 1, 0, 0, 0)).toISOString();
const periodEnd = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1, 0, 0, 0)).toISOString();

return [{
  json: {
    billing_month: billingMonth,
    period_start: periodStart,
    period_end: periodEnd,
    run_date: now.toISOString()
  }
}];

const payments = $input.first().json;
const billingData = $('Check: 1st of Month & Calc Period').first().json;

if (!Array.isArray(payments) || payments.length === 0) {
  return [{ json: { error: 'No active subscriptions found', ...billingData } }];
}

// Map stripe_payment_data fields to billing fields
return payments.map(p => {
  // Determine plan type and included minutes from the payment data
  const planName = (p.plan_name || '').toLowerCase();
  const isPremuim = planName.includes('premium');
  const includedMinutes = p.minutes ? parseInt(p.minutes) : (isPremuim ? 1000 : 475);

  return {
    json: {
      ...billingData,
      subscription_id: p.id,
      agent_id: p.agent_id,
      company_name: p.customer_name,
      client_email: p.customer_email,
      plan_type: isPremuim ? 'premium' : 'standard',
      included_minutes: includedMinutes,
      overage_rate_cents: 25,
      stripe_customer_id: p.stripe_customer_id,
      stripe_subscription_id: p.stripe_subscription_id
    }
  };
});

const calls = $input.first().json;
const sub = $('Split Into Individual Subscriptions').item;

// Calculate totals
const callList = Array.isArray(calls) ? calls : [];
const totalCalls = callList.length;
const totalSeconds = callList.reduce((sum, c) => sum + (c.duration_seconds || 0), 0);
const totalMinutes = Math.ceil(totalSeconds / 60); // Round UP to nearest minute
const includedMinutes = sub.json.included_minutes;

// Overage calculation
const overageMinutes = Math.max(0, totalMinutes - includedMinutes);
const overageRateCents = sub.json.overage_rate_cents || 25;
const overageAmountCents = overageMinutes * overageRateCents;

const usagePercent = includedMinutes > 0 ? Math.round((totalMinutes / includedMinutes) * 100) : 0;

return [{
  json: {
    ...sub.json,
    total_calls: totalCalls,
    total_seconds: totalSeconds,
    total_minutes: totalMinutes,
    included_minutes: includedMinutes,
    overage_minutes: overageMinutes,
    overage_rate_cents: overageRateCents,
    overage_amount_cents: overageAmountCents,
    overage_amount_dollars: (overageAmountCents / 100).toFixed(2),
    usage_percent: usagePercent,
    has_overage: overageMinutes > 0
  }
}];

